import{_ as d}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as n,c as h,a,b as e,d as t,w as r,e as c,r as i}from"./app.e17534bd.js";const p={},l=a("h2",{id:"简介",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),e(" 简介")],-1),f=a("p",null,[e("《JavaScript 高级程序设计》 是业界公认的 "),a("code",null,"JavaScript"),e(" 红宝书，书中简单介绍了 "),a("code",null,"JavaScript"),e(" 的历史，并由此展开，全面详实的介绍了 "),a("code",null,"JavaScript"),e(" 的相关知识。")],-1),S={href:"https://humanwhocodes.com/",target:"_blank",rel:"noopener noreferrer"},u=a("sup",{class:"footnote-ref"},[a("a",{href:"#footnote1"},"[1]"),a("a",{class:"footnote-anchor",id:"footnote-ref1"})],-1),v=a("sup",{class:"footnote-ref"},[a("a",{href:"#footnote2"},"[2]"),a("a",{class:"footnote-anchor",id:"footnote-ref2"})],-1),_=c('<p>这本书适合刚入门的前端人员阅读，也适合很多虽然工作很久但从未深入了解过这门语言的前端开发者。</p><h2 id="推荐原因" tabindex="-1"><a class="header-anchor" href="#推荐原因" aria-hidden="true">#</a> 推荐原因</h2><p>《JavaScript 高级程序设计》 是我刚入门前端时读的第一本前端书籍，因本人入门前端较晚，所以看的是第 4 版，在那个时侯，我只是简单的对 <code>HTML</code>、<code>CSS</code>、<code>JavaScript</code> 这三个网页组成部分有所了解，而这本书让我较为全面深入的了解了 <code>JavaScript</code> 这门语言。</p><p>不同于工具书籍，这本书并不仅仅是介绍 <code>JavaScript</code> 一些 Api 的作用，而是从历史出发，带我们了解这些 Api 的出现原因、作用以及解决了什么问题，比如 <code>let/const</code>、<code>class</code>、<code>Promise</code> 等等，让我收获颇丰，不愧 ‘红宝书’ 之名。</p><p>文章会对 《JavaScript 高级程序设计》 的全部章节进行简要总结，对于部分内容可能会另写单独的文章进行较为深入的讲解，这些文章会同步更新附录在对应章节下，对于其他书籍类的文章都会采用这种模式。</p><div class="custom-container tip"><p class="custom-container-title">提示</p><p>持续更新中</p></div><h2 id="章节" tabindex="-1"><a class="header-anchor" href="#章节" aria-hidden="true">#</a> 章节</h2><h3 id="第-1-章-什么是-javascript" tabindex="-1"><a class="header-anchor" href="#第-1-章-什么是-javascript" aria-hidden="true">#</a> 第 1 章 什么是 JavaScript</h3><p>通过本章知道了 JavaScript 的由来与发展，JavaScript 是 Brendan Eich 于 1995 年开发的一门脚本语言，一开始主要用于表单校验。</p><p>由于浏览器厂商相互竞争，出现了多个版本的 JavaScript，它们的实现不尽相同，为了统一 JavaScript 的语法与特性，规范被制定出来，被称为 ECMAScript。</p><p>JavaScript 并不完全等于 ECMAScript，JavaScript 包含三个部分</p><ul><li>ECMAScript</li><li>BOM</li><li>DOM</li></ul><h4 id="ecmascript" tabindex="-1"><a class="header-anchor" href="#ecmascript" aria-hidden="true">#</a> ECMAScript</h4><p>ECMAScript 只规定了不特定于平台的部分，像 <code>document</code>、<code>location</code> 这些 Api 就是特定于 Web 平台的，不特定于平台意味着只要引擎实现满足 ECMAScript 规范定义，那么只包含这部分的代码能够运行在任何平台下。</p><p>ECMAScript 版本之前以发布次数作为版本号，最近几年由于前端蓬勃发展，ECMAScript 每年都会发布一个新版本，所以目前以年份作为版本号，当然，普遍会将 ES2015 以后的版本统称为 ES6 或 ES6+。</p><h4 id="bom" tabindex="-1"><a class="header-anchor" href="#bom" aria-hidden="true">#</a> BOM</h4><p>BOM，浏览器对象模型，顾名思义，这部分特定于浏览器，提供的 Api 主要用于操作浏览器窗口。</p><h4 id="dom" tabindex="-1"><a class="header-anchor" href="#dom" aria-hidden="true">#</a> DOM</h4><p>DOM，文档对象模型，提供了操作网页文档的 Api，通过 DOM 能够实现页面的动态改变而无需请求一份新的网页文件。</p><p>DOM Level 1 映射文档结构，DOM Level 2 增加视图、事件、样式、遍历与范围等模块，DOM Level 3 新增加载、保存、验证文档的方法，且支持所有 XML 1.0 特性，DOM 4 新增 Mutation Events 与 Mutation Observers；目前不以 Level 维护 DOM。</p><h3 id="第-2-章-html-中的-javascript" tabindex="-1"><a class="header-anchor" href="#第-2-章-html-中的-javascript" aria-hidden="true">#</a> 第 2 章 HTML 中的 JavaScript</h3><p>通过本章了解了任何在 HTML 使用 JavaScript，并在浏览器不支持 JavaScript 时显示后置内容。</p><h4 id="script" tabindex="-1"><a class="header-anchor" href="#script" aria-hidden="true">#</a> script</h4><p><code>&lt;script&gt;</code> 元素可以用于加载外部 JavaScript 脚本，也能在元素内部直接书写 JavaScript 代码，他有许多属性，通过这些属性我们能够实现延迟执行、异步加载等功能。</p><p>通过 DOM Api 我们能够动态加载脚本，在 <code>&lt;script&gt;</code> 被添加到 DOM 前并执行前，对应的脚本不会被下载。</p><h4 id="noscript" tabindex="-1"><a class="header-anchor" href="#noscript" aria-hidden="true">#</a> noscript</h4><p><code>&lt;noscript&gt;</code> 元素在不支持 JavaScript 或相关功能被关闭的浏览器上会显示，用于告知用户相应的内容。</p><h3 id="第-3-章-语言基础" tabindex="-1"><a class="header-anchor" href="#第-3-章-语言基础" aria-hidden="true">#</a> 第 3 章 语言基础</h3><p>本章讲述了语言相关的基础知识，如语法、变量、数据类型、操作符、语句、函数等。</p><h4 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h4><p>JavaScript 的语法很大程度上借鉴了 C 语言，它区分大小写，标识符、注释都采用 C 风格，同时还描述了一组关键字与保留字。</p><h4 id="变量" tabindex="-1"><a class="header-anchor" href="#变量" aria-hidden="true">#</a> 变量</h4><p>ES6 以前使用 var 声明变量，现在已不再推荐使用，因为它具有很多不符合直觉的行为。</p>',33),b=a("h4",{id:"数据类型",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#数据类型","aria-hidden":"true"},"#"),e(" 数据类型")],-1),m=a("p",null,"JavaScript 有许多内置的数据类型，如 number、string、boolean、symbol、undefined、null 等基本数据类型，还有 object 引用数据类型。",-1),E=c('<h4 id="操作符" tabindex="-1"><a class="header-anchor" href="#操作符" aria-hidden="true">#</a> 操作符</h4><p>JavaScript 中拥有许多可用的操作符，如一元操作符、位操作符、布尔操作符、乘性操作符、加性操作符、关系操作符、相等操作符、条件操作符、复制操作符、逗号操作符等。</p><h4 id="语句" tabindex="-1"><a class="header-anchor" href="#语句" aria-hidden="true">#</a> 语句</h4><p>JavaScript 与其他语言一样，拥有多种语句，如 if、do-while、while、for、for-in、for-of、标签语句、break 与 continue、with、switch 等常用语句。</p><h4 id="函数" tabindex="-1"><a class="header-anchor" href="#函数" aria-hidden="true">#</a> 函数</h4><p>JavaScript 是 C 风格的语言，使用函数作为核心组件，使用函数封装语句以达到复用。</p><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="footnote1" class="footnote-item"><p>Nicholas C. Zakas：独立软件开发者，曾在 Yahoo 和 Box 任职，创建了 <code>ESLint</code> 开源项目，同时也是 《JavaScript 高级程序设计》 1~3 版的作者 <a href="#footnote-ref1" class="footnote-backref">↩︎</a></p></li><li id="footnote2" class="footnote-item"><p>Matt Frisbie：知名前端技术专家，曾在 Google 任职，目前担任 Gosellout 公司 CTO <a href="#footnote-ref2" class="footnote-backref">↩︎</a></p></li></ol></section>',8);function J(M,x){const s=i("ExternalLinkIcon"),o=i("RouterLink");return n(),h("div",null,[l,f,a("p",null,[e("《JavaScript 高级程序设计》 目前已更至第 4 版，于 2019 年出版发售，前三版的作者是 "),a("a",S,[e("Nicholas C. Zakas"),t(s)]),e(),u,e("，因病不能参与第 4 版的编写，第 4 版作者是 Matt Frisbie"),v,e("。")]),_,a("p",null,[t(o,{to:"/posts/javascript/es6/ES6-%E6%96%B0%E7%89%B9%E6%80%A7%E8%AF%A6%E8%A7%A3%20-%20let%E4%B8%8Econst.html"},{default:r(()=>[e("变量声明")]),_:1})]),b,m,a("p",null,[t(o,{to:"/posts/javascript/es6/ES6-%E6%96%B0%E7%89%B9%E6%80%A7%E8%AF%A6%E8%A7%A3-Symbol.html"},{default:r(()=>[e("symbol")]),_:1})]),E])}const O=d(p,[["render",J],["__file","JavaScript 高级程序设计.html.vue"]]);export{O as default};
